var html = result;
var pattern = /qsbs\.bb\('([^']+)'/g;
var matches = [];
var match;
while ((match = pattern.exec(html)) !== null) {
    matches.push(match[1]);
}
var content = '';
for (var i = 0; i < matches.length; i++) {
    try {
        var decoded = java.base64Decode(matches[i]);
        content += decoded;
    } catch (e) {

    }
}
content;
